(()=>{'use strict';
const $=s=>document.querySelector(s),$$=s=>[...document.querySelectorAll(s)];
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,'').replace(/[^0-9.\-]/g,''))||0;
const F=n=>N(n).toLocaleString('th-TH');
const B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const E=s=>T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
function activeName(){return T($('.tab.on')?.textContent)||'ถอดของ Pro'}
function thaiDate(){return new Date().toLocaleDateString('th-TH',{timeZone:'Asia/Bangkok',day:'numeric',month:'long',year:'numeric'})}
function selectedStore(){return T($('#sendText')?.textContent)||'-'}
function meta(title){return [['เอกสาร',title],['วันที่พิมพ์',thaiDate()],['วันที่',T($('#datesText')?.textContent).replace(/^วันที่:\s*/,'')||'ทั้งหมด'],['PS',T($('#psText')?.textContent).replace(/^PS:\s*/,'')||'ทั้งหมด'],['ส่งให้ร้าน',selectedStore()]]}
function rowsFromTable(){return $$('#table tbody tr').map(tr=>[...tr.children].map(td=>{const i=td.querySelector('input');return i?T(i.value):T(td.innerText)})).filter(r=>r.length&&r.join('').trim()&&!/ไม่มีข้อมูล|โหลดไฟล์|เลือก “ส่งให้ร้าน”/.test(r.join(' ')))}
function headsFromTable(){return $$('#table thead th').map(th=>T(th.innerText)).filter(Boolean)}
function state(){const keys=Object.keys(localStorage).filter(k=>/^doit-core-unified-v\d+:/.test(k));if(!keys.length)return{};const fl=T($('#fileLabel')?.textContent);let key=keys.find(k=>fl&&k.includes(fl))||keys[keys.length-1];try{return JSON.parse(localStorage.getItem(key)||'{}')||{}}catch{return{}}}
function parseKey(k){const p=String(k).split('|');return{type:p.at(-1)||'',sku:p.at(-2)||p.at(-1)||'',code:p.at(-3)||'',size:p.at(-4)||'',brand:p.at(-5)||'',store:p.at(-6)||selectedStore()}}
function visiblePickMap(){const m=new Map();$$('#table tbody tr').forEach(tr=>{const send=tr.querySelector('input[data-map="send"]'),add=tr.querySelector('input[data-map="add"]'),pull=tr.querySelector('input[data-map="pull"]');if(!send&&!add&&!pull)return;const k=send?.dataset.k||add?.dataset.k||pull?.dataset.k||'';const name=T(tr.children[1]?.querySelector('b')?.textContent)||parseKey(k).sku;const code=T(tr.children[1]?.querySelector('small')?.textContent).split('·')[0].trim();const base=N(tr.dataset.baseQty);const amt=N(T(tr.children[6]?.textContent));m.set(k,{name,code,unit:base?amt/base:0,remain:T(tr.querySelector('.remainCell')?.textContent)});});return m}
function pickRows(){const st=state(),vis=visiblePickMap(),out=[];const keys=[...new Set([...(Object.keys(st.send||{})),...(Object.keys(st.add||{})),...(Object.keys(st.pull||{}))])];keys.forEach(k=>{const s=N(st.send?.[k]),a=N(st.add?.[k]),p=N(st.pull?.[k]);if(!s&&!a&&!p)return;const v=vis.get(k)||{},x=parseKey(k),qty=s+a-p;out.push({code:v.code||x.code,name:v.name||x.sku,qty,send:s,add:a,pull:p,unit:N(v.unit),remain:v.remain||'',inserted:false});});(st.ins||[]).forEach(x=>out.push({code:T(x.code),name:T(x.name)||'สินค้าแทรก',qty:N(x.qty),send:N(x.qty),add:0,pull:0,unit:N(x.unit),remain:'',inserted:true}));return out.filter(x=>T(x.name))}
function openPrint(html){let st=$('#ctxPrintCss');if(!st){st=document.createElement('style');st.id='ctxPrintCss';st.textContent='.printOverlay{position:fixed;inset:0;background:#fff;z-index:9999;overflow:auto;color:#000}.printBar{position:sticky;top:0;background:#fff;border-bottom:1px solid #000;padding:8px;display:flex;justify-content:space-between}.receiptPage{font-family:system-ui,-apple-system,"Segoe UI",Tahoma,sans-serif;color:#111;width:194mm;min-height:281mm;margin:8px auto;padding:10mm;background:#fff}.receiptTop{display:flex;justify-content:space-between;gap:16px;border-bottom:3px solid #111;padding-bottom:10px;margin-bottom:12px}.receiptTitle{font-size:24px;font-weight:950;margin:0}.docBox{text-align:right;font-size:12px;line-height:1.7}.metaGrid{display:grid;grid-template-columns:1fr 1fr;gap:8px 16px;border:1px solid #111;padding:8px;margin-bottom:12px}.metaGrid div{font-size:13px}.metaGrid b{display:inline-block;min-width:78px}.receiptTable{width:100%;border-collapse:collapse;font-size:12px}.receiptTable th{background:#f3f4f6}.receiptTable th,.receiptTable td{border:1px solid #111;padding:5px;vertical-align:top}.r{text-align:right}.c{text-align:center}.totalRow td{font-weight:950;background:#f9fafb}.noteBox{border:1px solid #9ca3af;padding:8px;margin-top:12px;min-height:38px;font-size:12px}.signGrid{display:grid;grid-template-columns:1fr 1fr;gap:40px;margin-top:32px}.signBox{text-align:center;border-top:1px solid #111;padding-top:8px;font-size:13px}[contenteditable="true"]{outline:1px dashed transparent;cursor:text}[contenteditable="true"]:focus{outline:1px dashed #2563eb;background:#eff6ff}@media print{body>*:not(.printOverlay){display:none!important}.printBar{display:none!important}.printOverlay{position:static}.receiptPage{width:auto;min-height:auto;margin:0;padding:0}.receiptTable th{background:#eee!important;-webkit-print-color-adjust:exact;print-color-adjust:exact}}';document.head.appendChild(st)}const ov=document.createElement('div');ov.className='printOverlay';ov.innerHTML=`<div class="printBar"><b>ตรวจ/แก้ไขก่อนปริ้น</b><span><button onclick="this.closest('.printOverlay').remove()">ปิด</button> <button onclick="window.print()">ปริ้น</button></span></div>${html}`;document.body.appendChild(ov);return ov}
function formal(title,heads,rows,opt={}){if(!rows.length)return alert('ไม่มีข้อมูลสำหรับปริ้นในหน้า '+title);const doc='DOIT-'+Date.now().toString().slice(-8);const m=meta(title).map(([k,v])=>`<div contenteditable="true"><b>${E(k)}:</b> ${E(v)}</div>`).join('');const h=heads.map(x=>`<th>${E(x)}</th>`).join('');const b=rows.map((r,i)=>`<tr data-line><td class="c">${i+1}</td>${r.map((x,j)=>`<td class="${j>=2?'r':''} ${opt.calc&&j===2?'rq':''} ${opt.calc&&j===3?'ru':''} ${opt.calc&&j===4?'rt':''}" contenteditable="${opt.calc&&j===4?'false':'true'}">${E(x)}</td>`).join('')}</tr>`).join('');const foot=opt.total?`<tr class="totalRow"><td colspan="${heads.length-1}" class="r" contenteditable="true">รวมทั้งหมด</td><td class="r" id="ctxTotal">${E(opt.total)}</td></tr>`:'';const ov=openPrint(`<section class="receiptPage"><div class="receiptTop"><div><h1 class="receiptTitle" contenteditable="true">${E(title)}</h1></div><div class="docBox"><div contenteditable="true"><b>เลขที่เอกสาร:</b> ${E(doc)}</div></div></div><div class="metaGrid">${m}</div><table class="receiptTable"><thead><tr><th style="width:36px">#</th>${h}</tr></thead><tbody>${b}${foot}</tbody></table><div class="noteBox" contenteditable="true">หมายเหตุ: </div><div class="signGrid"><div class="signBox" contenteditable="true">ผู้ส่งสินค้า / ผู้จัดทำ</div><div class="signBox" contenteditable="true">ผู้รับสินค้า</div></div></section>`);if(opt.calc){const recalc=()=>{let total=0;ov.querySelectorAll('tr[data-line]').forEach(tr=>{const q=N(tr.querySelector('.rq')?.textContent),u=N(tr.querySelector('.ru')?.textContent),t=q*u;total+=t;const rt=tr.querySelector('.rt');if(rt)rt.textContent=B(t)});const tt=ov.querySelector('#ctxTotal');if(tt)tt.textContent=B(total)};ov.addEventListener('input',e=>{if(e.target.closest('.receiptTable'))recalc()});ov.addEventListener('blur',e=>{if(e.target.closest('.receiptTable'))recalc()},true);recalc();}}
function printPick(){const data=pickRows();const rows=data.map(x=>[x.code,x.name,F(x.qty),B(x.unit),B(x.qty*x.unit),x.inserted?'แทรกสินค้า':'คีย์เอง']);const total=B(data.reduce((s,x)=>s+x.qty*x.unit,0));formal('ใบจัดสินค้า / ถอดของ Pro',['รหัส','รายการสินค้า','จำนวน','ราคา/หน่วย','รวมเงิน','ประเภท'],rows,{calc:true,total});}
function printCurrent(){const name=activeName();if(name==='ถอดของ Pro')return printPick();const rows=rowsFromTable(),heads=headsFromTable();formal(name==='ใบส่งร้านจริง'?'ใบส่งสินค้า / ใบเสร็จรับเงิน':name,heads,rows)}
function bind(){const old=$('#prepPrint');if(!old)return false;const b=old.cloneNode(true);old.replaceWith(b);b.onclick=printCurrent;return true}
function boot(){if(!bind())setTimeout(boot,300)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();